@inject IJSRuntime JS
@implements IAsyncDisposable

<div @ref="_dropZoneRef" class="drop-zone @(_isDragOver ? "drag-over" : "")">
    <p class="drop-zone-text">Drag &amp; drop files here</p>
</div>

@if (_files.Count > 0)
{
    <ul class="file-list">
        @foreach (var entry in _files)
        {
            <li class="file-entry @(entry.Error is not null ? "file-error" : "")">
                <div class="file-info">
                    @if (entry.Error is not null)
                    {
                        <span class="error-message">@entry.Error</span>
                    }
                    else
                    {
                        <span class="file-name">@entry.Info!.Name</span>
                        <span class="file-size">@FormatSize(entry.Info!.Size)</span>
                        <span class="file-type">@(string.IsNullOrEmpty(entry.Info!.Type) ? "unknown" : entry.Info!.Type)</span>
                    }
                </div>
                <button class="btn-remove" @onclick="() => RemoveFile(entry)">Remove</button>
            </li>
        }
    </ul>
}

@code {
    private const long MaxFileSize = 10 * 1024 * 1024; // 10 MB

    [Parameter]
    public EventCallback<List<FileInfo>> OnFilesChanged { get; set; }

    private ElementReference _dropZoneRef;
    private IJSObjectReference? _module;
    private DotNetObjectReference<FileDropZone>? _dotNetRef;
    private bool _isDragOver;
    private readonly List<FileEntry> _files = new();

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _module = await JS.InvokeAsync<IJSObjectReference>(
                "import", "./_content/sv-930ee0865c194c2886bbeea8b2832ee8/Components/FileDropZone.razor.js");
            _dotNetRef = DotNetObjectReference.Create(this);
            await _module.InvokeVoidAsync("initDropZone", _dropZoneRef, _dotNetRef);
        }
    }

    [JSInvokable]
    public async Task OnDragStateChanged(bool isOver)
    {
        _isDragOver = isOver;
        await InvokeAsync(StateHasChanged);
    }

    [JSInvokable]
    public async Task OnFilesDropped(FileDropData[] droppedFiles)
    {
        _isDragOver = false;

        foreach (var file in droppedFiles)
        {
            if (file.Size > MaxFileSize)
            {
                _files.Add(new FileEntry(
                    new FileInfo(file.Name, file.Size, file.Type),
                    $"\"{file.Name}\" exceeds the 10 MB limit ({FormatSize(file.Size)})"));
            }
            else
            {
                _files.Add(new FileEntry(new FileInfo(file.Name, file.Size, file.Type), null));
            }
        }

        await NotifyParent();
        await InvokeAsync(StateHasChanged);
    }

    private async Task RemoveFile(FileEntry entry)
    {
        _files.Remove(entry);
        await NotifyParent();
    }

    private async Task NotifyParent()
    {
        var accepted = _files
            .Where(f => f.Error is null)
            .Select(f => f.Info!)
            .ToList();
        await OnFilesChanged.InvokeAsync(accepted);
    }

    private static string FormatSize(long bytes) => bytes switch
    {
        < 1024 => $"{bytes} B",
        < 1024 * 1024 => $"{bytes / 1024.0:F1} KB",
        _ => $"{bytes / (1024.0 * 1024.0):F1} MB"
    };

    public async ValueTask DisposeAsync()
    {
        if (_module is not null)
        {
            try { await _module.InvokeVoidAsync("dispose", _dropZoneRef); } catch { }
            await _module.DisposeAsync();
        }
        _dotNetRef?.Dispose();
    }

    // Internal types
    private sealed record FileEntry(FileInfo? Info, string? Error);

    public sealed record FileDropData(string Name, long Size, string Type);
}

.drop-zone {
    display: flex;
    align-items: center;
    justify-content: center;
    min-height: 160px;
    border: 2px dashed #6c757d;
    border-radius: 8px;
    background-color: #f8f9fa;
    transition: background-color 0.2s, border-color 0.2s;
    cursor: default;
}

.drop-zone.drag-over {
    background-color: #d4edda;
    border-color: #28a745;
}

.drop-zone-text {
    color: #6c757d;
    font-size: 1.1rem;
    margin: 0;
    pointer-events: none;
}

.file-list {
    list-style: none;
    padding: 0;
    margin-top: 1rem;
}

.file-entry {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 0.5rem 0.75rem;
    border: 1px solid #dee2e6;
    border-radius: 4px;
    margin-bottom: 0.4rem;
}

.file-entry.file-error {
    border-color: #dc3545;
    background-color: #fff5f5;
}

.file-info {
    display: flex;
    gap: 1rem;
    flex-wrap: wrap;
    align-items: center;
}

.file-name {
    font-weight: 600;
}

.file-size,
.file-type {
    color: #6c757d;
    font-size: 0.9rem;
}

.error-message {
    color: #dc3545;
    font-weight: 500;
}

.btn-remove {
    background: none;
    border: 1px solid #dc3545;
    color: #dc3545;
    border-radius: 4px;
    padding: 0.2rem 0.6rem;
    cursor: pointer;
    font-size: 0.85rem;
    transition: background-color 0.15s, color 0.15s;
}

.btn-remove:hover {
    background-color: #dc3545;
    color: #fff;
}

const handlers = new Map();

export function initDropZone(element, dotNetRef) {
    let dragCounter = 0;

    function onDragEnter(e) {
        e.preventDefault();
        dragCounter++;
        if (dragCounter === 1) {
            dotNetRef.invokeMethodAsync('OnDragStateChanged', true);
        }
    }

    function onDragOver(e) {
        e.preventDefault();
    }

    function onDragLeave(e) {
        e.preventDefault();
        dragCounter--;
        if (dragCounter === 0) {
            dotNetRef.invokeMethodAsync('OnDragStateChanged', false);
        }
    }

    function onDrop(e) {
        e.preventDefault();
        dragCounter = 0;

        const files = Array.from(e.dataTransfer.files).map(f => ({
            name: f.name,
            size: f.size,
            type: f.type
        }));

        dotNetRef.invokeMethodAsync('OnFilesDropped', files);
    }

    element.addEventListener('dragenter', onDragEnter);
    element.addEventListener('dragover', onDragOver);
    element.addEventListener('dragleave', onDragLeave);
    element.addEventListener('drop', onDrop);

    handlers.set(element, { onDragEnter, onDragOver, onDragLeave, onDrop });
}

export function dispose(element) {
    const h = handlers.get(element);
    if (h) {
        element.removeEventListener('dragenter', h.onDragEnter);
        element.removeEventListener('dragover', h.onDragOver);
        element.removeEventListener('dragleave', h.onDragLeave);
        element.removeEventListener('drop', h.onDrop);
        handlers.delete(element);
    }
}

